optimized_federated_query:
# Smart Federated Query with Class Constraints
# Note: Multiple class interpretations exist but all route to same endpoints
# A single query retrieves all data regardless of class ambiguity

SELECT DISTINCT ?ChemicalEquation ?ReactionTitle ?compound ?drug ?drugDesc ?molecularWeightAverage
WHERE {

  SERVICE <http://localhost:8892/sparql/> {
    ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/description> ?drugDesc . # ?drug:drugs, ?drugDesc:Literal
    ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/drugType> <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugtype/smallMolecule> .
    ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/keggCompoundId> ?compound .
    OPTIONAL {
    ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/molecularWeightAverage> ?molecularWeightAverage . # ?drug:drugs, ?molecularWeightAverage:Literal
      FILTER (?molecularWeightAverage > 114)
    }
  }

  SERVICE <http://localhost:8895/sparql/> {
    ?Chemicalreaction <http://purl.org/dc/elements/1.1/title> ?ReactionTitle . # ?Chemicalreaction:Reaction, ?ReactionTitle:Literal
    ?Chemicalreaction <http://bio2rdf.org/ns/kegg#xEnzyme> ?enzyme . # ?Chemicalreaction:Reaction, ?enzyme:Enzyme
    ?Chemicalreaction <http://bio2rdf.org/ns/kegg#equation> ?ChemicalEquation . # ?Chemicalreaction:Reaction, ?ChemicalEquation:Literal
    ?enzyme <http://bio2rdf.org/ns/kegg#xSubstrate> ?compound . # ?enzyme:Enzyme, ?compound:Compound
  }
}
LIMIT 1000
